import type { Lang } from './digiclara';

type Video = {
  title: string;
  url: string;
  embed: string;
};

type Media = {
  src: string;
  alt: string;
  caption: string;
};

export type ArticleBodyBase = {
  quick: string[];
  sections: [string, string[]][];
  steps: string[];
  tips: string[];
  warnings: string[];
  faq: [string, string][];
  conclusion: string;
  video?: Video;
  media?: Media[];
};

type Copy = {
  quick: string[];
  contextTitle: string;
  context: string[];
  decisionTitle: string;
  decision: string[];
  practiceTitle: string;
  practice: string[];
  steps: string[];
  tips: string[];
  warnings: string[];
  faq: [string, string][];
  conclusion: string;
  video?: Video;
  media?: Media[];
};

const body = (copy: Copy): ArticleBodyBase => ({
  quick: copy.quick,
  sections: [
    [copy.contextTitle, copy.context],
    [copy.decisionTitle, copy.decision],
    [copy.practiceTitle, copy.practice],
  ],
  steps: copy.steps,
  tips: copy.tips,
  warnings: copy.warnings,
  faq: copy.faq,
  conclusion: copy.conclusion,
  ...(copy.video ? { video: copy.video } : {}),
  ...(copy.media ? { media: copy.media } : {}),
});

